mapper.select:
select *
from batch.approval_command
where tenant_id = #{tenantId}
  and approval_no = #{approvalNo}

mapper.update:
update batch.approval_command
set approval_status = #{approvedStatus},
    approver_id = #{approverId},
    approval_reason = #{approvalReason},
    approved_at = current_timestamp,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and approval_no = #{approvalNo}
  and approval_status = #{pendingStatus}

update batch.approval_command
set approval_status = #{rejectedStatus},
    approver_id = #{approverId},
    approval_reason = #{approvalReason},
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and approval_no = #{approvalNo}
  and approval_status = #{pendingStatus}

update batch.approval_command
set approval_status = #{executedStatus},
    executed_at = current_timestamp,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and approval_no = #{approvalNo}
  and approval_status = #{approvedStatus}

mapper.select:
select *
from batch.approval_command
where tenant_id = #{tenantId}
  and approval_status = #{pendingStatus}
order by created_at asc
limit #{limit}
